parameters.jsCode:
const output = $input.first().json.text || 
               $input.first().json.output || 
               $input.first().json.content || '';

let briefs = output
  .split('===BRIEF_START===')
  .map(p => p.trim())
  .filter(p => p.length > 100);

if (briefs.length === 0) {
  briefs = output
    .split(/(?=\[\s*UPFRONT)/)
    .map(p => p.trim())
    .filter(p => p.length > 100);
}

if (briefs.length === 0) {
  briefs = [output.trim()];
}

const messages = briefs.map((brief) => ({
  json: { brief: brief.trim().substring(0, 4000) }
}));

messages.push({
  json: {
    brief: `====================================
[ UPFRONT // TEAM NOTE ]
====================================

3 briefs above. Use them as direction.
Not final copy. You bring the execution.

HOW TO USE
lead line     — starting point not final
visual prompt — refine before generating
post times    — adjust based on your read
seed comment  — 30 min after posting. always.

AFTER POSTING
tick Posted in Notion
add Saves and Reposts after 48 hours
this feeds next week

deadline — all 3 live before Sunday midnight
====================================`
  }
});

return messages;

